window.ERAS = [{"id":"taino-riverlands","index":1,"label":"Taíno Riverlands","yearStart":1400,"yearEnd":1492,"anchorYear":1450,"isNew":false,"confidence":"low","confidenceReason":"No paleoecological core at the Ozama mouth; the river-mouth's pre-1500 look is inferred from ecoregion + colonial descriptions + modern mangrove remnants.","summary":"A tidal, mangrove-fringed estuary where the Ozama meets the Caribbean. Taíno villages of palm-thatch bohíos sit among conuco mound-gardens; dugout canoes ply a river shared with manatees and herons. Low, green, horizontal — no stone, no walls.","palette":{"colors":["#1f3d2b","#2f6b4f","#7fae86","#c9b98f","#2a7d8c","#12435a"],"mood":"Deep forest and mangrove greens; silver-brown tidal mudflats; turquoise-to-deep Caribbean; earth-brown batey plazas and thatch; faint smoke from managed burns."},"layers":{"sky":"Clear tropical sky, faint haze of managed-burn and cooking smoke on the horizon.","water":"Brackish tidal estuary, calm; mangrove reflections; a manatee wake.","westBank":"Limestone bluff cloaked in dry/semi-deciduous forest and royal palms; a small bohío village with a cleared batey plaza and surrounding conuco mound-gardens.","eastBank":"Lower, marshier bank of red/black/white mangrove fringe grading to freshwater swamp forest.","vegetation":["mangrove","royal-palm","dry-semi-deciduous-forest","columnar-cactus","conuco-gardens"],"fauna":["west-indian-manatee","american-crocodile","heron","egret","rhinoceros-iguana","hutia","pelican","frigatebird"],"structures":[],"humanActivity":["bohio-village","batey-plaza","conuco-mound-gardens","dugout-canoe","fishing"],"ambient":["drifting-canoe","wading-heron","surfacing-manatee","rising-smoke-wisp"]},"hotspots":[{"name":"Bohío village & batey","detail":"Palm-thatch houses (round for commoners, rectangular caney for chiefs) around a cleared, packed-earth central plaza used for the areíto ceremony.","confidence":"moderate"},{"name":"Conuco gardens","detail":"Raised mound-plots of yuca, sweet potato, maize, beans, peppers, cotton and tobacco; mounding cut erosion and improved drainage. Yuca was grated and baked into casabe.","confidence":"high"},{"name":"Manatee in the estuary","detail":"West Indian manatees, crocodiles and sea turtles used the brackish mouth. Regionally documented; site-specific records are thin.","confidence":"moderate"}],"panels":{"landscape":"The natural cover is Hispaniolan subtropical dry / semi-deciduous forest on the limestone terraces, fringed at the tidal mouth by red, black and white mangroves grading to freshwater swamp forest and royal palms. The Cibao pollen record shows a palm-rich landscape already shaped by small-scale fire and conuco clearings from ~AD 1150 — a mosaic of forest, gardens and village, not wholesale clearing.","fauna":"The signature 'lost fauna' — Hispaniolan hutia and solenodon — plus West Indian manatee, American crocodile, sea turtles, land crabs and rhinoceros iguana. Mangroves host herons and egrets; pelicans and frigatebirds work the mouth.","hydrology":"The Ozama (148 km) meets the Caribbean here and joins the Isabela in a tidal, mangrove-fringed estuary about 10 km long — brackish and navigable, which is why every later settler chose it. Limestone bluffs on the west bank; a lower, marshier east bank.","built":"None. No stone architecture, walls, draft animals or wheels — a low, organic, green profile broken only by palms and thin columns of smoke.","people":"Taíno villages of bohíos around a batey, tied to river fishing and conuco farming. Island-wide population estimates span ~250,000 to 1,000,000+ (Spanish claims of 3–4M are exaggerations); there is no reliable count for the Ozama-mouth villages."},"metrics":{"treeCover":96,"builtArea":1,"population":2},"sources":[{"title":"Hispaniolan Dry Forests (One Earth)","url":"https://www.oneearth.org/ecoregions/hispaniolan-dry-forests/"},{"title":"Columbus' footprint / Laguna Biajaca core","url":"https://www.sciencedirect.com/science/article/abs/pii/S2213305418300304"},{"title":"Hispaniolan hutia","url":"https://en.wikipedia.org/wiki/Hispaniolan_hutia"},{"title":"Return to Hispaniola: demographic reassessment","url":"https://read.dukeupress.edu/hahr/article/83/1/3/26855/Return-to-Hispaniola-Reassessing-a-Demographic"}]},{"id":"contact-founding","index":2,"label":"Contact & Founding","yearStart":1492,"yearEnd":1502,"anchorYear":1498,"isNew":false,"confidence":"high","confidenceReason":"Founding events well documented; the surrounding ecology is still the inferred Era-1 estuary.","summary":"The last green frame before the grid. A small timber-and-thatch European settlement is grafted onto the still-wild estuary on the EAST bank (1496). The Columbian Exchange begins — the first cattle, pigs, horses and dogs land — and a 1502 hurricane will wreck the town.","palette":{"colors":["#2f6b4f","#8a9b6e","#b5652f","#c9b98f","#2a7d8c","#6b4a2f"],"mood":"Native greens and blues intact but scarred: cleared timber, mud, a raw wooden fort, ship masts at the mouth, smoke."},"layers":{"sky":"Tropical sky; a gathering hurricane haze as an optional late-era mood.","water":"Estuary with the first European ships — a caravel/nao at anchor near the mouth.","westBank":"Still-forested limestone bluff — the future city site, as yet unbuilt.","eastBank":"A raw wooden settlement: a stockade, thatch-and-timber houses, cut stumps, mud, cleared forest edge.","vegetation":["mangrove","royal-palm","dry-semi-deciduous-forest","cut-stumps"],"fauna":["west-indian-manatee","heron","iguana","first-cattle","first-pig","first-horse","war-dog"],"structures":[{"name":"First settlement (La Nueva Isabela / Santo Domingo)","bank":"east","builtBy":1496,"confidence":"high"}],"humanActivity":["timber-felling","stockade-building","ships-at-anchor","first-livestock"],"ambient":["anchored-caravel","drifting-canoe","tethered-horse","rising-smoke-wisp"]},"hotspots":[{"name":"Bartolomé Colón's settlement (1496)","detail":"Columbus's brother founded the first town on the EAST bank of the Ozama mouth, chosen for its harbor, fresh water and a nearby Taíno village that sheltered the near-starving Spaniards.","confidence":"high"},{"name":"The 1502 hurricane","detail":"A devastating hurricane wrecked the east-bank town; incoming governor Nicolás de Ovando decided to rebuild on the WEST bank — the permanent site.","confidence":"high"},{"name":"The first livestock","detail":"Cattle, pigs, horses and dogs arrive with the Columbian Exchange. Feral pigs exploded within a decade — the governor issued hunting licenses because they had 'spiraled out of control.'","confidence":"high"}],"panels":{"landscape":"Overwhelmingly the Era-1 forest, mangrove and estuary, now with a small timber-and-thatch European settlement grafted on. The Columbian Exchange's biological invasion is just beginning: the first Old World animals and plants land in these years.","fauna":"Native estuarine fauna still dominant — manatee, crocodile, hutia, iguana, birds — now joined by the first Iberian livestock and war-dogs. One frame can show a manatee and mangrove alongside the first tethered horse and pig: the hinge moment.","hydrology":"Unchanged natural estuary, now a working anchorage — European ships ride at the mouth for the first time.","built":"A raw wooden settlement on the east bank (from 1496): a stockade, thatch-and-timber houses, cut stumps and mud — no stone yet. The 1502 hurricane erases it.","people":"About 200 initial settlers. Taíno collapse is already underway from violence, forced labor and epidemic disease."},"metrics":{"treeCover":92,"builtArea":3,"population":2},"sources":[{"title":"Santo Domingo (Wikipedia)","url":"https://en.wikipedia.org/wiki/Santo_Domingo"},{"title":"Santo Domingo (Britannica)","url":"https://www.britannica.com/place/Santo-Domingo"},{"title":"Ecological impact of the Columbian Exchange","url":"https://www.thecollector.com/ecological-impact-columbian-exchange/"}]},{"id":"ovando-grid-sugar","index":3,"label":"Ovando's Grid & Sugar Boom","yearStart":1502,"yearEnd":1586,"anchorYear":1540,"isNew":false,"confidence":"high","confidenceReason":"Architecture and dates are firm; the extent of local deforestation for sugar is documented island-wide but less precisely mapped at the mouth.","summary":"The frame flips. Ovando lays out the first planned European grid city in the Americas on the WEST bank; golden coral-stone architecture rises — the Fortaleza Ozama, the Alcázar, the first cathedral. Sugar mills and fuelwood cutting fell the forest; feral herds turn cleared land to savanna.","palette":{"colors":["#c9a34e","#b5652f","#8a7d5a","#9caa78","#2a6d7c","#d8c9a0"],"mood":"Warm cream/ochre coral-stone, red-tile roofs, the pale keep and cathedral tower; deforested tan-green savanna replacing dark forest; galleons and mill smoke."},"layers":{"sky":"Bright, imperial; mill smoke smudging the inland horizon.","water":"Busy anchorage — galleons and caravels at the river-mouth port.","westBank":"The rectilinear grid city: coral-limestone buildings, red-tile roofs, the Fortaleza Ozama on the SE tip, the Alcázar on the bluff, the cathedral tower, the beginnings of the muralla wall.","eastBank":"Cleared savanna and cane fields; cattle; cutover forest.","vegetation":["cane-fields","cleared-savanna","remnant-gallery-forest","introduced-grasses"],"fauna":["cattle-herd","horse","pig","manatee-retreating"],"structures":[{"name":"Fortaleza Ozama / Torre del Homenaje","bank":"west","builtBy":1508,"confidence":"high"},{"name":"Alcázar de Colón","bank":"west","builtBy":1512,"confidence":"high"},{"name":"Catedral Primada de América","bank":"west","builtBy":1540,"confidence":"high"},{"name":"Puerta de las Atarazanas (shipyards/customs)","bank":"west","builtBy":1540,"confidence":"high"},{"name":"City walls (muralla, begun)","bank":"west","builtBy":1550,"confidence":"moderate"}],"humanActivity":["grid-city","sugar-ingenio","enslaved-labor","galleon-port","cattle-ranching"],"ambient":["sailing-galleon","mill-smoke","cart-on-quay"]},"hotspots":[{"name":"Fortaleza Ozama (1502–08)","detail":"The oldest European military structure in the Americas, on the SE tip commanding the river mouth. Its Torre del Homenaje keep dates 1503–05. This is the skyline anchor for every later era.","confidence":"high"},{"name":"Ovando's grid (1502)","detail":"The first planned European grid city in the Americas; the plan survives intact in today's Ciudad Colonial and became the template for New World town planning.","confidence":"high"},{"name":"Sugar mills & the falling forest","detail":"By 1520 the island had ~24 water-powered ingenios plus animal-powered trapiches, sited by rivers and forests for water power and fuelwood — driving deforestation of the lowland dry and gallery forest.","confidence":"high"},{"name":"Slavery & the 1521 revolt","detail":"Enslaved Africans replaced the collapsing Indigenous labor force (~2,000/yr mid-century). The 1521 revolt on a Diego Colón sugar estate is the first documented enslaved-African uprising in the Americas.","confidence":"high"}],"panels":{"landscape":"This is when the forest starts falling at scale. Cane fields and fuelwood cutting for the sugar mills clear the lowland dry and gallery forest, including in the Ozama drainage; after sugar's decline, feral cattle and pigs convert cleared land to ranch savanna (hatos), and introduced grasses reshape the vegetation.","fauna":"Native fauna is in retreat near the city; cattle, horses and pigs now dominate the landscape. Manatee and crocodile persist only in quieter estuary reaches.","hydrology":"The river mouth is a busy treasure-fleet port early in the century — galleons at anchor — until Havana's better position siphons the trade off later.","built":"Golden coral-limestone architecture rises on the west bank: the Fortaleza Ozama (1502–08), Alcázar de Colón (1510–12), Calle Las Damas (oldest paved street in the Americas), the Catedral Primada (completed 1540), first hospital, first university, and the beginnings of the city walls.","people":"Santo Domingo is the capital of the Spanish Indies. Taíno collapse is near-total — ~32,000 by 1514, ~200 by 1565 — while enslaved Africans are imported in growing numbers."},"metrics":{"treeCover":70,"builtArea":18,"population":6},"sources":[{"title":"Primeros Ingenios Coloniales (UNESCO tentative list)","url":"https://whc.unesco.org/en/tentativelists/6291/"},{"title":"1521 Santo Domingo Slave Revolt","url":"https://en.wikipedia.org/wiki/1521_Santo_Domingo_Slave_Revolt"},{"title":"Ciudad Colonial (Santo Domingo)","url":"https://en.wikipedia.org/wiki/Ciudad_Colonial_(Santo_Domingo)"},{"title":"Colonial City of Santo Domingo (UNESCO WHS 526)","url":"https://whc.unesco.org/en/list/526/"}]},{"id":"fortress-stagnation","index":4,"label":"Fortress City & Stagnation","yearStart":1586,"yearEnd":1795,"anchorYear":1690,"isNew":false,"confidence":"high","confidenceReason":"Events (Drake, sieges, wall-building) well documented; partial forest regrowth around the shrunken city is a reasonable inference.","summary":"Faded grandeur. Drake sacks and burns the city in 1586, ending its first-tier importance. Gold gone and the fleet shifted to Havana, Santo Domingo becomes a poor cattle-and-hides town behind a slowly built defensive wall; forest partly reclaims the quiet hinterland.","palette":{"colors":["#8a8574","#a9976a","#6f7d5a","#9a8b6f","#3a6d7c","#c2b79a"],"mood":"Weathered grey-ochre stone, empty plazas, a modest port, ranch land and scrub beyond the walls, tropical decay and quiet."},"layers":{"sky":"Muted, hazy, quiet.","water":"A quieter port — small craft and hide-export coasters, not treasure galleons.","westBank":"The walled colonial city at roughly today's footprint — Fortaleza, cathedral, Alcázar, walls and bastions — weathered and under-maintained.","eastBank":"Ranch savanna and secondary scrub/forest regrowth; scattered cattle.","vegetation":["secondary-scrub","ranch-savanna","regrowth-forest","remnant-mangrove"],"fauna":["feral-cattle","feral-pig","feral-horse","manatee","crocodile"],"structures":[{"name":"City walls & bastions (muralla, ~6 gates, ~20 bastions)","bank":"west","builtBy":1700,"confidence":"high"},{"name":"Fortaleza Ozama (weathered)","bank":"west","builtBy":1508,"confidence":"high"}],"humanActivity":["walled-town","cattle-hides-trade","small-port","pirate-threat"],"ambient":["small-coaster","grazing-cattle","gull"]},"hotspots":[{"name":"Drake's sack (1586)","detail":"Sir Francis Drake sacked and burned Santo Domingo and held it for ransom — a hinge event that ended the city's first-tier importance.","confidence":"high"},{"name":"The muralla","detail":"The defensive wall — roughly 6 gates and ~20 bastions, batteries and watchtowers — was built and rebuilt piecemeal across about two centuries in response to the pirate threat. The 1655 English Penn & Venables attempt was repelled.","confidence":"high"},{"name":"Cattle, hides & the feral frontier","detail":"Gold exhausted and the fleet shifted to Havana, the colony became a poor cattle-and-hides society. Crown-forced depopulations left much of the island empty — the feral-herd frontier French buccaneers later colonized.","confidence":"high"}],"panels":{"landscape":"Long stagnation and rural depopulation. Vegetation partly reverts to secondary scrub, regrowth forest and open ranch savanna around a shrunken city; the estuary and mangroves are relatively undisturbed compared to the sugar peak.","fauna":"Feral cattle, pigs and horses are now the defining large fauna of the interior; native estuarine species persist in the quieter mouth.","hydrology":"The river-mouth port is quieter — working small craft and hide exports rather than treasure galleons.","built":"The walled city stands at roughly today's footprint — Fortaleza, cathedral, Alcázar, walls and bastions — but weathered, under-maintained, with low building activity.","people":"A poor, thinly populated society. After gold ran out and colonists left for Mexico and Peru, the town subsists on cattle, hides and a modest port."},"metrics":{"treeCover":74,"builtArea":20,"population":5},"sources":[{"title":"Drake's Sack of Santo Domingo","url":"https://sites.utexas.edu/culturescontexts/2014/03/28/francis-drakes-sack-of-santo-domingo-a-case-of-terrorism/"},{"title":"Santo Domingo under Siege 1585–86 (Library of Congress)","url":"https://www.loc.gov/item/2021670164/"},{"title":"La Muralla de Santo Domingo","url":"https://www.ecured.cu/La_Muralla_de_Santo_Domingo"}]},{"id":"french-haitian-unification","index":5,"label":"French Rule & Haitian Unification","yearStart":1795,"yearEnd":1844,"anchorYear":1822,"isNew":false,"confidence":"high","confidenceReason":"The sequence of foreign rule and abolition is well documented; the physical landscape barely changes (inference).","summary":"The same weathered stone city changes flags again and again — Spain cedes to France (1795), Toussaint occupies (1801), then España Boba, then the 1822–44 Haitian Unification governs the whole island and abolishes slavery. In 1844 independence is proclaimed at the Puerta del Conde.","palette":{"colors":["#8a8574","#9a8b6f","#6f7d5a","#7a6a55","#3a6d7c","#b6ab8e"],"mood":"Weathered stone, shifting military uniforms, agrarian poverty, a still-natural estuary. Contested, worn, provincial."},"layers":{"sky":"Overcast, subdued.","water":"Sleepy estuary, a few sailing craft.","westBank":"The neglected walled city; the Puerta del Conde gate prominent.","eastBank":"Subsistence farms, cattle, natural estuary edge.","vegetation":["subsistence-plots","ranch-savanna","regrowth-forest","mangrove"],"fauna":["cattle","manatee","heron"],"structures":[{"name":"Puerta del Conde (Baluarte del Conde)","bank":"west","builtBy":1655,"confidence":"high"},{"name":"Neglected colonial fabric & walls","bank":"west","builtBy":1700,"confidence":"high"}],"humanActivity":["shifting-garrisons","abolition","subsistence-farming","independence-1844"],"ambient":["marching-soldiers","small-sailing-craft"]},"hotspots":[{"name":"The changing flags (1795–1821)","detail":"1795 Treaty of Basel cedes the colony to France; 1801 Toussaint Louverture occupies and abolishes slavery; 1802–09 French 'Era de Francia'; 1809–21 Spanish 'España Boba.'","confidence":"high"},{"name":"Haitian Unification (1822–1844)","detail":"The whole island is governed from Port-au-Prince under Boyer; slavery is abolished, large estates broken up and church lands seized. Physically the city changes little.","confidence":"high"},{"name":"Independence at the Puerta del Conde (1844)","detail":"Dominican independence was proclaimed at this gate on 27 February 1844 — the symbolic heart of the nation.","confidence":"high"}],"panels":{"landscape":"Political churn brings economic contraction; plantations are dismantled or depressed and land reverts toward subsistence farming and cattle. There is no major new hydrological or built transformation of the river mouth — the change is human and political, not landscape.","fauna":"Unchanged from the quiet colonial estuary — cattle inland, native species persisting at the mouth.","hydrology":"A sleepy natural estuary and modest port, as in the previous era.","built":"Colonial fabric persists, somewhat neglected; the city stays small and walled. The Puerta del Conde becomes the symbolic site of the 1844 independence declaration.","people":"A city of low tens of thousands living through foreign rule, abolition and, in 1844, the birth of the Republic."},"metrics":{"treeCover":73,"builtArea":21,"population":6},"sources":[{"title":"Era de Francia","url":"https://en.wikipedia.org/wiki/French_occupation_of_Santo_Domingo"},{"title":"Unification of Hispaniola (1822–1844)","url":"https://en.wikipedia.org/wiki/Unification_of_Hispaniola"},{"title":"Puerta del Conde (Baluarte del Conde)","url":"https://en.wikipedia.org/wiki/Baluarte_del_Conde"}]},{"id":"young-republic","index":6,"label":"The Young Republic","yearStart":1844,"yearEnd":1882,"anchorYear":1870,"isNew":true,"confidence":"high","confidenceReason":"The town's ruined state, economy and the 1865 evacuation are documented (incl. Hazard's 1873 account); exact local deforestation from logging is inference.","summary":"The landscape of the new nation right after the Haitian Unification: a small, half-ruined provincial town of 2,000–3,000 people inside its old wall. The Fortaleza Ozama is a vine-covered ruin; hardwood-log rafts drift to the port. The 1865 Spanish scorched evacuation leaves much of the city in rubble.","palette":{"colors":["#d8cdb0","#b7a678","#7d8a5f","#9c6b45","#8a4b3a","#4a6d78"],"mood":"Sun-bleached and melancholy — bone white, ochre, moss green, rust, faded indigo; vines reclaiming stone; empty streets; a quiet river of sailing craft and logs."},"layers":{"sky":"Bleached, hot, still.","water":"Quiet river with small sailing coasters (schooners/brigs) and log booms.","westBank":"A modest town of wooden houses among colonial ruins; the Fortaleza Ozama moss- and vine-overgrown; the Cathedral and a few church towers the only skyline; the old wall still ringing it.","eastBank":"Thinned gallery forest and cutover patches; oxcarts of hardwood logs; palm-thatch cabins.","vegetation":["thinned-gallery-forest","cutover-patches","mangrove","scrub","vines-on-ruins"],"fauna":["cattle","heron","manatee"],"structures":[{"name":"Fortaleza Ozama (ruined, vine-covered)","bank":"west","builtBy":1508,"confidence":"high"},{"name":"Catedral Primada","bank":"west","builtBy":1540,"confidence":"high"},{"name":"City wall & Puerta del Conde","bank":"west","builtBy":1655,"confidence":"high"},{"name":"Colonial stone ruins (post-1865 evacuation)","bank":"west","builtBy":1865,"confidence":"high"}],"humanActivity":["mahogany-logging","log-rafts","cattle-hatos","small-port","wooden-town"],"ambient":["log-raft-drift","small-schooner","oxcart"]},"hotspots":[{"name":"A town in its own rubble","detail":"Traveler Samuel Hazard (1873) described a decayed town of ~2,000–3,000, rebuilt in modest wooden houses among colonial stone ruins — the Fortaleza garrisoned by twelve men with one working musket and rusty, unfireable cannon.","confidence":"high"},{"name":"Mahogany & logwood","detail":"The southern region's precious-woods trade (caoba, guayacán, campeche) shipped from the Ozama-mouth port. Draw oxcarts and rafts of hardwood logs, log booms in the river, and small sailing coasters at the wharf.","confidence":"high"},{"name":"The 1865 scorched evacuation","detail":"Santana engineered a Spanish re-annexation in 1861; the Restoration War (1863–65) was fought mostly in the interior, but the mark on this view is the 1865 Spanish scorched evacuation that flattened much of the built fabric.","confidence":"high"}],"panels":{"landscape":"Agrarian and export-thin. Cattle ranching (hatos), subsistence crops and a southern mahogany/logwood trade. Selective riverine logging thins the gallery forest along the lower Ozama, but island-wide clear-cutting is still a 20th-century story — keep it modest here.","fauna":"Little changed ecologically — cattle inland, herons and the odd manatee at a quiet mouth.","hydrology":"A working but modest port: hardwood logs, log booms and small sailing craft rather than steamers.","built":"A small, half-ruined provincial town inside its 16th-century wall — not a grand capital. Wooden houses, palm-thatch cabins on the outskirts, colonial stone warehouses standing as ruins, and a crumbling Fortaleza Ozama.","people":"Roughly 2,000–3,000 people in the 1870s, living through caudillo instability (Santana, Báez), the 1861–65 Spanish annexation and the Restoration War."},"metrics":{"treeCover":68,"builtArea":22,"population":6},"sources":[{"title":"Fortaleza Ozama","url":"https://en.wikipedia.org/wiki/Fortaleza_Ozama"},{"title":"Spanish annexation of the Dominican Republic","url":"https://en.wikipedia.org/wiki/Spanish_annexation_of_the_Dominican_Republic"},{"title":"Dominican Restoration War","url":"https://en.wikipedia.org/wiki/Dominican_Restoration_War"},{"title":"Caribbean maritime heritage — DR ports","url":"https://maritimeheritage.org/ports/caribbeanDominicanRepublic.html"}]},{"id":"breaking-the-walls","index":7,"label":"Breaking the Walls","yearStart":1882,"yearEnd":1930,"anchorYear":1910,"isNew":false,"confidence":"high","confidenceReason":"The bridge, electrification and expansion are documented; some riverfront industrial detail is inference.","summary":"The city breaks its walls. Under Ulises Heureaux the first bridge crosses the Ozama (1878), electric lamps arrive in the 1890s, and the town spills past the colonial walls. Industrial sugar returns, steamships work the mouth, and a lift-bridge later rises the deck for river traffic.","palette":{"colors":["#b9a67a","#c7b184","#8f9b6a","#9a7d55","#5a7d88","#d5c8a6"],"mood":"Belle-époque tropical — iron bridge, gas/electric lamps, telegraph poles, steamships and lighters, pastel town houses past the old grey walls, cane on the horizon, first industrial smoke."},"layers":{"sky":"Brighter, hopeful; thin industrial smoke.","water":"A working modern port — steamships and lighters; the first Ozama bridge spanning the river.","westBank":"The colonial core with pastel town houses spreading beyond partly demolished walls; gas/electric street lamps, telegraph poles.","eastBank":"Semi-rural Villa Duarte ('Pajarito') beginning as an informal riverside settlement; cane fields.","vegetation":["cane-fields","pasture","remnant-mangrove","garden-plots"],"fauna":["cattle","heron","gull"],"structures":[{"name":"First Ozama bridge (iron-and-wood, Crosby)","bank":"span","builtBy":1878,"confidence":"high"},{"name":"Ulises Heureaux lift bridge","bank":"span","builtBy":1917,"confidence":"high"},{"name":"Electric street lighting","bank":"west","builtBy":1896,"confidence":"high"}],"humanActivity":["first-bridge","electrification","steamship-port","industrial-sugar","expansion-past-walls"],"ambient":["steamship-smoke","lift-bridge-deck-rising","lamplight-flicker"]},"hotspots":[{"name":"The first Ozama bridge (1878)","detail":"An iron-and-wood span by engineer Howard Crosby, inaugurated under president Ulises Heureaux ('Lilís') — the first fixed link between the west-bank core and the east bank. A lift bridge followed on the same piers ~1914–1917.","confidence":"high"},{"name":"Electric lamps & telegraph","detail":"Heureaux-era modernization brought electric street lighting in the 1890s, plus telephone, telegraph and railways. The city began expanding beyond its colonial walls.","confidence":"high"},{"name":"Villa Duarte begins","detail":"On the still-semi-rural east bank, Villa Duarte ('Pajarito') originates as an informal riverside settlement in the late 19th century.","confidence":"high"}],"panels":{"landscape":"Continued conversion of surrounding land to cane and pasture; mangroves still present, but the urban riverfront turns industrial as wharves and the first bridge engineer the banks.","fauna":"Estuarine wildlife thinning against an industrializing waterfront; cattle and cane define the surroundings.","hydrology":"The mouth becomes a working modern port again — steamships and lighters — and the first bridge and wharves begin engineering the riverbanks.","built":"The city breaks its walls: the 1878 iron bridge, 1890s electric lamps, telegraph and railways, and pastel town houses spreading past the partly demolished muralla. Industrial sugar centrales return, mainly to the east and southeast.","people":"A modernizing belle-époque capital, still small but newly connected across the river and lit at night for the first time."},"metrics":{"treeCover":58,"builtArea":30,"population":9},"sources":[{"title":"Historia del Río Ozama y sus puentes","url":"http://losminadigital.blogspot.com/2017/07/la-historia-de-los-puentes-sobre-el-rio.html"},{"title":"Five main bridges of Santo Domingo","url":"https://inmobiliario.do/en/the-five-main-bridges-of-santo-domingo/"},{"title":"Villa Duarte","url":"https://en.wikipedia.org/wiki/Villa_Duarte"}]},{"id":"ciudad-trujillo","index":8,"label":"Trujillo's Ciudad Trujillo","yearStart":1930,"yearEnd":1961,"anchorYear":1955,"isNew":false,"confidence":"high","confidenceReason":"The hurricane, rebuild, renaming, monuments and growth are well documented; early riverbank encroachment is inference.","summary":"The modern city is forged. Weeks after Trujillo takes power, Hurricane San Zenón (1930) levels the city; he rebuilds and monumentalizes it, renames it Ciudad Trujillo (1936), lays the Malecón and the Las Américas highway, and stages the 1955 world's fair. Population leaps from under 100,000 to ~400,000.","palette":{"colors":["#e0dccf","#c4b48c","#7f9068","#9a9488","#4a7d8c","#eef0ea"],"mood":"Authoritarian modernism — white monumental architecture, wide boulevards, the coastal Malecón, mid-century cars, neon of the 1955 fair; the colonial core preserved as a showpiece."},"layers":{"sky":"Clear, bright, triumphal.","water":"Modernized port; bridges over the Ozama; coastal Malecón to the west.","westBank":"White monumental civic architecture and wide new avenues around the preserved colonial core; the Malecón waterfront.","eastBank":"Sprawl jumping the Ozama in earnest — Villa Duarte / Ensanche Benefactor formalized; the Las Américas highway heading east.","vegetation":["suburban-lots","agricultural-fringe","shrinking-mangrove","boulevard-trees"],"fauna":["few-birds","shrinking-estuary-life"],"structures":[{"name":"Rebuilt monumental city (post-San Zenón)","bank":"west","builtBy":1940,"confidence":"high"},{"name":"Malecón waterfront","bank":"west","builtBy":1945,"confidence":"high"},{"name":"Feria de la Paz (1955 world's fair / Centro de los Héroes)","bank":"west","builtBy":1956,"confidence":"high"},{"name":"Las Américas Highway","bank":"east","builtBy":1955,"confidence":"high"}],"humanActivity":["reconstruction","monumentalism","east-bank-sprawl","malecon-boulevards"],"ambient":["mid-century-cars","fair-neon","flag-parade"]},"hotspots":[{"name":"Hurricane San Zenón (1930)","detail":"Weeks after Trujillo took power, San Zenón devastated the city — thousands dead, 'reduced to rubble.' Trujillo used the reconstruction to seize control of who got housing and to remake the city.","confidence":"high"},{"name":"Ciudad Trujillo (1936–1961)","detail":"The city was renamed Ciudad Trujillo in 1936 (reverting to Santo Domingo in 1961). Population grew from under 100,000 in 1930 to roughly 400,000 by 1961.","confidence":"high"},{"name":"The 1955 Feria de la Paz","detail":"A world's-fair complex (now Centro de los Héroes) of modernist civic buildings — the monumental quarter west of the colonial zone.","confidence":"high"}],"panels":{"landscape":"Surrounding land turns agricultural and then rapidly suburban; native estuarine habitat shrinks against the growing city, and mangrove margins begin to be encroached by early informal settlement.","fauna":"Estuarine wildlife in steep retreat as the city and its roads canalize the riverbanks.","hydrology":"The port is modernized and new bridges and roadworks engineer the banks; the Malecón fixes a hard coastal edge to the west.","built":"State-driven modernism: a rebuilt monumental core, new avenues and ministries, the Malecón, the Las Américas highway east to the airport, and the 1955 world's-fair quarter — with the colonial stone core kept as a showpiece.","people":"Population roughly doubles each decade; sprawl jumps the Ozama onto the east bank in earnest, with Villa Duarte and Ensanche Benefactor formalized."},"metrics":{"treeCover":42,"builtArea":48,"population":14},"sources":[{"title":"San Zenón hurricane 1930 (DR1)","url":"https://dr1.com/news/2022/09/05/the-san-zenon-hurricane-hit-santo-domingo-92-years-ago/"},{"title":"Fair of Peace and Fraternity of the Free World (1955)","url":"https://en.wikipedia.org/wiki/Fair_of_Peace_and_Fraternity_of_the_Free_World"},{"title":"Trujillo — Colonial Zone DR","url":"https://www.colonialzone-dr.com/trujillo/"}]},{"id":"upheaval-concrete-boom","index":9,"label":"Upheaval & the Concrete Boom","yearStart":1961,"yearEnd":1978,"anchorYear":1965,"isNew":true,"confidence":"high","confidenceReason":"The 1965 war, US intervention and Balaguer construction boom are well documented; exact per-barrio founding dates are inference.","summary":"Rupture, then a bulldozed boom. Trujillo is assassinated (1961); the 1965 civil war and US intervention turn the Duarte Bridge over the Ozama into a battlefield. Then Balaguer's 'Twelve Years' pour concrete — broad new avenues, brutalist blocks — as migration explodes the barrios down to the riverbanks.","palette":{"colors":["#9a9488","#6f6a5a","#8a5a3a","#7d8a5f","#4a5d6a","#b0483a"],"mood":"1965: harsh, high-contrast, olive-drab, black tank smoke, dust, red. 1966–78: raw optimism — wet concrete grey, cranes, cement haze, hot sun on new white buildings."},"layers":{"sky":"Smoke and dust in 1965; cement haze in the boom years.","water":"The Duarte Bridge over the Ozama — the pivotal crossing; port working below.","westBank":"The old city and Ciudad Nueva (rebel-held in 1965); new Balaguer avenues, overpasses and brutalist multifamiliares rising; cranes and cement dust.","eastBank":"Growth jumping the Ozama toward the future Santo Domingo Este; the first flood-prone riverbank squatter settlements (La Ciénaga / Los Guandules / Gualey) taking hold.","vegetation":["cleared-lots","shrinking-riverbank-green","scattered-palms"],"fauna":["few-birds"],"structures":[{"name":"Puente Duarte (battle site, 1965)","bank":"span","builtBy":1955,"confidence":"high"},{"name":"New avenues (Churchill, JFK, 27 de Febrero)","bank":"west","builtBy":1975,"confidence":"high"},{"name":"Brutalist multifamiliares","bank":"west","builtBy":1975,"confidence":"high"},{"name":"Early riverbank barrios","bank":"east","builtBy":1970,"confidence":"moderate"}],"humanActivity":["civil-war-1965","us-intervention","concrete-construction","rural-urban-migration","riverbank-squatting"],"ambient":["burning-tank-smoke","construction-crane","cement-dust-haze"]},"hotspots":[{"name":"Battle of the Duarte Bridge (1965)","detail":"In the April 1965 civil war the Puente Duarte over the Ozama — the key west–east crossing — became the pivotal chokepoint: loyalist tanks stalled and were captured in tight streets, and air-strafing shattered buildings west of the bridge. The 82nd Airborne then secured the entire east bank.","confidence":"high"},{"name":"Operation Power Pack","detail":"The US intervention landed ~22,500 troops; rebels held Ciudad Nueva in the old city, and roughly 2,000–4,000 people were killed across the fighting. Draw sandbagged checkpoints, paratroopers in colonial streets, and barricades.","confidence":"high"},{"name":"Balaguer's Twelve Years","detail":"A 1966–78 construction frenzy funded by high sugar prices and US aid: broad new avenues (Churchill, JFK, 27 de Febrero), overpasses, brutalist multifamiliares and ministries — while rural-to-urban migration exploded the barrios.","confidence":"high"}],"panels":{"landscape":"The boom clears land wholesale for avenues and housing; the riverbanks begin their transformation from green edge to informal settlement.","fauna":"Estuarine wildlife largely displaced from the urban reach as construction and squatting reach the water.","hydrology":"Growth jumps the Ozama to the east bank, tied to the Duarte Bridge; informal settlement of the low, flood-prone riverbanks takes hold — the seed of La Ciénaga, Los Guandules and Gualey.","built":"First the 1965 war damage in the old city and around the Duarte Bridge; then Balaguer's concrete frenzy — straight arterials, raw overpasses, poured-concrete blocks rising beside older low fabric, a city visibly under construction.","people":"Rupture (Trujillo's assassination, civil war, foreign intervention) gives way to explosive rural-to-urban migration; the city 'expands uncontrollably.'"},"metrics":{"treeCover":30,"builtArea":60,"population":28},"sources":[{"title":"Battle of Duarte Bridge","url":"https://en.wikipedia.org/wiki/Battle_of_Duarte_Bridge"},{"title":"Dominican Civil War","url":"https://en.wikipedia.org/wiki/Dominican_Civil_War"},{"title":"Operation Power Pack (US Army CSI)","url":"https://www.armyupress.army.mil/Portals/7/combat-studies-institute/csi-books/PowerPack.pdf"},{"title":"Joaquín Balaguer (Britannica)","url":"https://www.britannica.com/biography/Joaquin-Balaguer"}]},{"id":"democracy-urban-explosion","index":10,"label":"Democracy & Urban Explosion","yearStart":1978,"yearEnd":1998,"anchorYear":1992,"isNew":true,"confidence":"high","confidenceReason":"The democratic turn, Faro a Colón, barrio densification and Hurricane Georges are documented; the apagones-as-texture framing is a reasonable inference.","summary":"A young democracy in hard times. The 1978 peaceful transfer of power meets 1980s crisis, food riots and chronic blackouts. In 1992 the colossal Faro a Colón rises on the east bank, its laser cross so power-hungry it darkened the barrios. The Ozama banks pack with informal neighborhoods; Hurricane Georges floods them in 1998.","palette":{"colors":["#1c1f2a","#e0a850","#3a6ea5","#8a8a7a","#7a9b7a","#c05a4a"],"mood":"Chaotic, energetic, unequal, often literally dark — night ambers and generator glow pierced by a surreal blue laser cross; neon Malecón vs. unlit barrios; 1998 flood browns."},"layers":{"sky":"Night scene option: dark sky with a blue cross-beam; or storm grey for 1998.","water":"A dirtying river packed at the banks with informal housing; floodwater in the Georges variant.","westBank":"The old city and a denser modern skyline; neon Malecón nightlife; frequent blackouts.","eastBank":"The colossal supine cross of the Faro a Colón; dense riverbank barrios (La Ciénaga, Los Guandules, Gualey, Guachupita) stacked to the water.","vegetation":["minimal-riverbank-green","water-hyacinth","scattered-trees"],"fauna":["few-birds"],"structures":[{"name":"Faro a Colón (Columbus Lighthouse)","bank":"east","builtBy":1992,"confidence":"high"},{"name":"Dense riverbank barrios","bank":"east","builtBy":1990,"confidence":"high"},{"name":"Malecón nightlife strip","bank":"west","builtBy":1985,"confidence":"moderate"}],"humanActivity":["first-peaceful-transfer","apagones","faro-laser-cross","barrio-densification","hurricane-georges-flood"],"ambient":["laser-cross-beam","generator-glow","flood-water-rising"]},"hotspots":[{"name":"Faro a Colón (1992)","detail":"Built 1986–92 on the east bank for the Columbus quincentenary — a colossal supine cross ~210 m long and ~10 stories, its cross-shaped sky-beams visible ~70 km. So power-hungry that lighting it darkened surrounding barrios; its construction involved mass evictions and a 'wall of shame' hiding the slums.","confidence":"high"},{"name":"Democracy & the 1980s crisis","detail":"August 1978 saw the country's first peaceful transfer of power between elected presidents. The 1980s brought inflation, IMF austerity, the April 1984 food riots, and chronic apagones (blackouts) — a city often lit by generators and candles.","confidence":"high"},{"name":"Hurricane Georges (1998)","detail":"On 22 September 1998 Georges swelled the Ozama and flooded the riverbank barrios; a youth hostel collapsed into the river, killing six, with ~380+ dead and ~155,000 homeless nationally.","confidence":"high"}],"panels":{"landscape":"The riverbanks are now packed informal neighborhoods — tin-and-block houses stacked down steep banks to a polluted river — with only scraps of green and mats of water hyacinth.","fauna":"The urban estuary is effectively emptied of its native wildlife; water hyacinth and trash mark the water.","hydrology":"A dirtying, encroached river that turns deadly in flood — Hurricane Georges swallows riverside shacks in 1998.","built":"The signature new monument is the 1992 Faro a Colón on the east bank; opposite, the old city and a denser modern skyline, with Malecón nightlife along the Caribbean seafront.","people":"A young democracy through hard times — surreal spectacle (the laser cross) beside real poverty (the unlit barrios it darkened)."},"metrics":{"treeCover":18,"builtArea":74,"population":55},"sources":[{"title":"Columbus Lighthouse (Faro a Colón)","url":"https://en.wikipedia.org/wiki/Columbus_Lighthouse"},{"title":"Columbus cross controversy (CS Monitor, 1992)","url":"https://www.csmonitor.com/1992/1009/09061.html"},{"title":"DR — Bosch, Balaguer & successors (Britannica)","url":"https://www.britannica.com/place/Dominican-Republic/Bosch-Balaguer-and-their-successors"},{"title":"Effects of Hurricane Georges in the DR","url":"https://en.wikipedia.org/wiki/Effects_of_Hurricane_Georges_in_the_Dominican_Republic"}]},{"id":"new-millennium","index":11,"label":"The New Millennium","yearStart":1998,"yearEnd":2015,"anchorYear":2009,"isNew":true,"confidence":"high","confidenceReason":"The banking crisis, Metro and waterfront projects are documented; exact tower-boom timing is a reasonable inference.","summary":"A capital reaching for 'world city' status while the river rots at its feet. The 2003 Baninter crash halves the peso; then the Caribbean's first metro opens (2009/2013), Sans Souci redevelops the east-bank waterfront, and glass towers rise in Piantini — as the Ozama is finally named an environmental crisis.","palette":{"colors":["#8a94a0","#b8c2cc","#5a6d7a","#6f8a5f","#4a5d55","#7a6a4a"],"mood":"Modernizing and aspirational but scarred — crisis-grey early, then glassy optimism; new metro viaducts and first glass towers over a low older city; a visibly dirty brown-green river."},"layers":{"sky":"Hazy urban blue.","water":"A visibly polluted river — brown water, green hyacinth, trash lines — with the Sans Souci terminal on the east-bank mouth.","westBank":"The old core with elevated Metro Line 1 viaducts slicing above the avenues; a rising cluster of glass towers inland (Piantini/Naco).","eastBank":"Sans Souci port/terminal redevelopment on the Av. España corridor; continued sprawl into Santo Domingo Este.","vegetation":["water-hyacinth","minimal-green","boulevard-trees"],"fauna":["few-birds"],"structures":[{"name":"Santo Domingo Metro Line 1 (elevated)","bank":"west","builtBy":2009,"confidence":"high"},{"name":"Metro Line 2 (underground)","bank":"west","builtBy":2013,"confidence":"high"},{"name":"Sans Souci port / cruise terminal","bank":"east","builtBy":2010,"confidence":"high"},{"name":"Piantini/Naco glass towers","bank":"west","builtBy":2012,"confidence":"moderate"}],"humanActivity":["banking-crisis","metro-opens","waterfront-redevelopment","highrise-boom","pollution-named"],"ambient":["metro-train-gliding","crane","hyacinth-drift"]},"hotspots":[{"name":"The Baninter crash (2003)","detail":"The collapse of Banco Intercontinental (a ~55bn-peso fraud) plus Bancrédito and Mercantil; the bailout consumed ~15% of GDP, the peso lost about half its value, and inflation spiked toward ~35% in 2003 — stalling construction and sending protesters into the streets.","confidence":"high"},{"name":"The Caribbean's first metro","detail":"Santo Domingo Metro Line 1 opened in 2009 (largely elevated viaducts down the avenues) and Line 2 in 2013 (largely underground) — the most extensive metro in the insular Caribbean and Central American region.","confidence":"high"},{"name":"Sans Souci & the glass skyline","detail":"The Sans Souci cruise-terminal and master-plan redevelopment rose on the east bank at the Ozama mouth, while a vertical boom of glass-and-concrete towers climbed in Piantini and Naco inland.","confidence":"high"}],"panels":{"landscape":"The contrast sharpens — new elevated infrastructure and first glass towers above a low older city, with the river openly dirty (brown water, green hyacinth, trash lines).","fauna":"The urban estuary remains effectively lifeless; the pollution crisis is now named publicly ahead of the 2020 cleanup.","hydrology":"The Ozama is now recognized as a heavily polluted urban river — raw sewage, solid waste, floating trash and water-hyacinth mats.","built":"The Metro (2009/2013), Sans Souci waterfront redevelopment, the Av. España corridor, and a rising inland skyline of towers; sprawl continues into Santo Domingo Este and Norte.","people":"A boom interrupted by the 2003 crisis, then a modernizing, aspirational capital reaching for 'world city' status."},"metrics":{"treeCover":13,"builtArea":86,"population":80},"sources":[{"title":"Banco Intercontinental (Baninter)","url":"https://en.wikipedia.org/wiki/Banco_Intercontinental"},{"title":"Santo Domingo Metro","url":"https://en.wikipedia.org/wiki/Santo_Domingo_Metro"},{"title":"Sans Souci cruise terminal","url":"https://www.adelte.com/project/santo-domingo-sans-souci-cruise-terminal/"},{"title":"INTEC: Ozama transfers ~90% of waste to the sea","url":"https://www.intec.edu.do/en/notas-de-prensa/item/el-rio-ozama-transfiere-un-90-de-residuos-al-mar-caribe-se-determina-en-una-investigacion"}]},{"id":"modern-megacity","index":12,"label":"Modern Megacity","yearStart":2015,"yearEnd":2026,"anchorYear":2024,"isNew":false,"confidence":"high","confidenceReason":"Bridges, teleférico, Interceptor 004, wetlands park, La Nueva Barquita and population are documented; the '~90,000 tons/yr' plastic tonnage is press-cited only — cite the 40–90% figure instead.","summary":"A proud, fast-modernizing capital wrestling openly with its river. Red teleférico cabins glide over the riverbank barrios; the Juan Bosch bridge and Metro extend the city; the Ocean Cleanup's Interceptor 004 works the polluted mouth; and La Nueva Barquita rehouses flood-prone residents while remnant mangroves survive at the edges.","palette":{"colors":["#8a95a0","#c05a4a","#5a6d7a","#3f7d55","#6a5f4a","#c9d2d8"],"mood":"Dense, kinetic, layered — red teleférico cabins over grey-turquoise tin roofs; sleek bridges and metro viaducts; a glassy inland skyline; the industrial Interceptor at a murky mouth; green mangroves at the edges."},"layers":{"sky":"Hazy megacity blue.","water":"The murky brown-green Ozama with the Interceptor 004 barge and floating trash booms angled across the mouth; the Juan Bosch bridge downstream.","westBank":"The preserved pale colonial core on the bluff (a UNESCO World Heritage Site) beneath a dense modern city and glassy inland skyline.","eastBank":"The Faro cross and port cranes; red teleférico cabins on cables over the tin roofs of Gualey/Los Guandules; pastel relocation blocks; remnant mangroves and the Humedales wetlands to the north.","vegetation":["remnant-mangrove","humedales-wetland","water-hyacinth","street-trees"],"fauna":["few-birds","wetland-birds-upstream"],"structures":[{"name":"Puente Juan Bosch","bank":"span","builtBy":2016,"confidence":"high"},{"name":"Teleférico (cable car) over the Ozama","bank":"east","builtBy":2018,"confidence":"high"},{"name":"Ocean Cleanup Interceptor 004","bank":"water","builtBy":2020,"confidence":"high"},{"name":"La Nueva Barquita relocation blocks","bank":"east","builtBy":2016,"confidence":"high"},{"name":"Faro a Colón","bank":"east","builtBy":1992,"confidence":"high"}],"humanActivity":["teleferico-transit","new-bridges","river-cleanup","riverbank-relocation","megacity-life"],"ambient":["gliding-gondola","interceptor-conveyor","traffic-flow","drifting-plastic"]},"hotspots":[{"name":"The teleférico (2018)","detail":"The Caribbean's first urban gondola flies a ~5 km line across the Ozama (twice), its red cabins gliding directly over the tin roofs of Gualey and Los Guandules and the brown river — linking long-isolated riverbank barrios to Metro Line 2. The single most drawable 'modern' motif for this view.","confidence":"high"},{"name":"Interceptor 004 & the plastic","detail":"The Ozama transfers an estimated 40–90% of its floating plastic straight to the Caribbean. The Ocean Cleanup's Interceptor 004 — the first in the Caribbean — was installed in 2020: a catamaran-style barge with a floating boom angled across the mouth. (The widely-quoted '~90,000 tons/yr' is press-cited, not confirmed in a primary source — we cite the percentage.)","confidence":"high"},{"name":"Mangroves & La Nueva Barquita","detail":"Parque Nacional Humedales del Ozama (~47 km²) preserves lagoons and mangroves north of the city — the last patch of the Era-1 estuary. La Nueva Barquita (2016) rehoused ~5,500–6,000 flood-prone riverbank residents in 112 planned blocks on higher ground; Nuevo Domingo Savio continues the riverbank renewal.","confidence":"high"}],"panels":{"landscape":"A dense concrete megacity with a struggling river at its heart; surviving nature is confined to remnant mangroves and the Humedales wetland fragments at the edges.","fauna":"Native estuarine fauna is largely gone from the urban reach — manatee rare or absent, crocodile pushed upstream — with wetland birds persisting only in the protected fragments.","hydrology":"The lower Ozama is heavily engineered and severely polluted; the Interceptor 004 and floating barriers now work the mouth, and flood-prone residents have been relocated off the banks.","built":"New Ozama crossings (Juan Bosch, 2016) and the teleférico (2018) thread over the barrios; the preserved colonial core is a UNESCO World Heritage Site; the Faro cross and port cranes anchor the east bank.","people":"City proper ~1.04M (2020); Greater Santo Domingo metro ~3.3M — the Caribbean's largest metropolis — modern infrastructure layered over persistent poverty and a struggling river."},"metrics":{"treeCover":12,"builtArea":92,"population":100},"sources":[{"title":"Santo Domingo cable car (teleférico)","url":"https://en.wikipedia.org/wiki/Santo_Domingo_cable_car"},{"title":"Puente Juan Bosch","url":"https://en.wikipedia.org/wiki/Puente_Juan_Bosch"},{"title":"Ocean Cleanup — Interceptor 004 (first in the Caribbean)","url":"https://theoceancleanup.com/updates/interceptor-004-the-first-in-the-carribean/"},{"title":"La Nueva Barquita","url":"https://www.wastefreeoceans.org/lanuevabarquita"},{"title":"Greater Santo Domingo population","url":"https://en.wikipedia.org/wiki/Greater_Santo_Domingo"}]}];
window.META = {"place":"Mouth of the Ozama River, Santo Domingo, Dominican Republic","vantage":"Fixed viewpoint looking across the Ozama mouth toward the SE tip (Fortaleza Ozama) on the west bank, with the east bank beyond.","metricsNote":"treeCover / builtArea / population are normalized 0-100 illustrative estimates for relative-change sparklines only. They encode documented direction and rough magnitude, not survey figures. population is normalized to the ~3.3M metro of 2020 = 100.","confidenceLevels":{"high":"Documented — firm primary/architectural/event record.","moderate":"Partly documented / reasonable inference from adjacent evidence.","low":"Reconstructed inference — plausible, thinly sourced; draw with caution."}};
